const hamburger=document.querySelector(".hamburger"),navMenu=document.querySelector(".nav-menu");hamburger.addEventListener("click",()=>{navMenu.classList.toggle("active")}),document.querySelectorAll(".nav-link").forEach(e=>e.addEventListener("click",()=>{navMenu.classList.remove("active")})),document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",function(e){e.preventDefault();document.querySelector(this.getAttribute("href")).scrollIntoView({behavior:"smooth",block:"start"})})});let lastScrollY=0,ticking=!1;window.addEventListener("scroll",()=>{ticking||(window.requestAnimationFrame(()=>{const e=document.querySelector(".navbar"),t=window.scrollY;t>lastScrollY&&t>100?e.classList.add("transparent"):(t<lastScrollY||t<=100)&&e.classList.remove("transparent"),lastScrollY=t,ticking=!1}),ticking=!0)});